241	    fn next(&mut self) -> Option<Self::Item> {
242	        while let Some(c) = unsafe { NonNull::new(self.curr.as_ptr() as *mut Entry) } {
243	            let succ = unsafe { c.as_ref().next.load(Acquire, self.guard) };
244	
245	            if succ.tag() == 1 {
246	                // This entry was removed. Try unlinking it from the list.
247	                let succ = succ.with_tag(0);
248	
249	                // The tag should always be zero, because removing a node after a logically deleted
250	                // node leaves the list in an invalid state.
251	                debug_assert!(self.curr.tag() == 0);
252	
253	                // Try to unlink `curr` from the list, and get the new value of `self.pred`.
254	                let succ = match self
255	                    .pred
256	                    .compare_exchange(self.curr, succ, Acquire, Acquire, self.guard)
257	                {
258	                    Ok(_) => {
259	                        // We succeeded in unlinking `curr`, so we have to schedule
260	                        // deallocation. Deferred drop is okay, because `list.delete()` can only be
261	                        // called if `T: 'static`.
262	                        unsafe {
263	                            C::finalize(self.curr.as_ptr(), self.guard);
264	                        }
265	
266	                        // `succ` is the new value of `self.pred`.
267	                        succ
268	                    }
269	                    Err(e) => {
270	                        // `e.current` is the current value of `self.pred`.
271	                        e.current
272	                    }
273	                };
274	
275	                // If the predecessor node is already marked as deleted, we need to restart from
276	                // `head`.
277	                if succ.tag() != 0 {
278	                    self.pred = self.head;
279	                    self.curr = self.head.load(Acquire, self.guard);
280	
281	                    return Some(Err(IterError::Stalled));
282	                }
283	
284	                // Move over the removed by only advancing `curr`, not `pred`.
285	                self.curr = succ;
286	                continue;
287	            }
288	
289	            // Move one step forward.
290	            self.pred = unsafe { &(*c.as_ptr()).next };
291	            self.curr = succ;
292	
293	            return Some(Ok(unsafe { &*C::element_of(c.as_ptr()) }));
294	        }
295	
296	        // We reached the end of the list.
297	        None
